using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration including feature flags and limits.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = "Production",
            MaxConnections = 100,
            RequestTimeoutSeconds = 30,
            Features = new
            {
                DarkMode = true,
                BetaAccess = false,
                MaintenanceMode = false
            },
            AllowedOrigins = new[] { "https://example.com", "https://app.example.com" }
        };

        return JsonSerializer.Serialize(config, JsonOptions);
    }

    [McpServerResource(
        UriTemplate = "config://app/version",
        Name = "App Version",
        MimeType = "application/json"),
     Description("Returns the application version and build metadata.")]
    public static string GetVersionInfo()
    {
        var version = new
        {
            Version = "2.5.1",
            BuildDate = "2026-04-07",
            GitCommit = "abc1234"
        };

        return JsonSerializer.Serialize(version, JsonOptions);
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool(ReadOnly = true), Description("Looks up the value of a specific configuration key.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. 'MaxConnections', 'Environment')")] string key)
    {
        var settings = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase)
        {
            ["Environment"] = "Production",
            ["MaxConnections"] = 100,
            ["RequestTimeoutSeconds"] = 30,
            ["DarkMode"] = true,
            ["BetaAccess"] = false,
            ["MaintenanceMode"] = false
        };

        if (settings.TryGetValue(key, out var value))
            return JsonSerializer.Serialize(new { Key = key, Value = value }, JsonOptions);

        return JsonSerializer.Serialize(new { Key = key, Error = "Key not found" }, JsonOptions);
    }

    [McpServerTool(ReadOnly = true), Description("Lists all available configuration keys.")]
    public static string ListConfigKeys()
    {
        var keys = new[]
        {
            "Environment", "MaxConnections", "RequestTimeoutSeconds",
            "DarkMode", "BetaAccess", "MaintenanceMode"
        };

        return JsonSerializer.Serialize(new { Keys = keys }, JsonOptions);
    }
}

